mapper.select:
SELECT btr.book_id, COUNT(*) as tag_match_count
FROM book_tag_relation btr
WHERE btr.tag_id IN

    #{tagId}

AND btr.book_id != #{excludeBookId}
GROUP BY btr.book_id
ORDER BY tag_match_count DESC
LIMIT #{limit}

SELECT b.id
FROM book b
WHERE b.category_id = #{categoryId}
AND b.id != #{excludeBookId}
ORDER BY b.hot_score DESC, b.average_score DESC
LIMIT #{limit}
